CREATE TABLE SALUTATION (ID INTEGER GENERATED BY DEFAULT AS IDENTITY (START WITH 1 INCREMENT BY 1) NOT NULL, SALUTATION VARCHAR(255), PRIMARY KEY (ID))
CREATE TABLE CUSTOMER (ID INTEGER GENERATED BY DEFAULT AS IDENTITY (START WITH 1 INCREMENT BY 1) NOT NULL, BIRTHDAY DATE, FILENAME VARCHAR(200), FIRSTNAME VARCHAR(255), IMAGE LONGVARBINARY, LASTNAME VARCHAR(255), PRIVATECUSTOMER BOOLEAN, EMAIL VARCHAR(255), TELEPHONE_OFFICE VARCHAR(255), TELEPHONE_PRIVATE VARCHAR(255), HEALTHINSURANCE_ID INTEGER, SALUTATION_ID INTEGER, PRIMARY KEY (ID))
CREATE TABLE HEALTHINSURANCE (ID INTEGER GENERATED BY DEFAULT AS IDENTITY (START WITH 1 INCREMENT BY 1) NOT NULL, CITY VARCHAR(255), HEALTH_INSURANCE VARCHAR(255), STREET VARCHAR(255), ZIP INTEGER, PRIMARY KEY (ID))
CREATE TABLE ADDRESS (ID INTEGER GENERATED BY DEFAULT AS IDENTITY (START WITH 1 INCREMENT BY 1) NOT NULL, CITY VARCHAR(255), STREET VARCHAR(255), ZIP VARCHAR(4), CUSTOMER_ID INTEGER, PRIMARY KEY (ID))
CREATE TABLE EDUCATION (ID INTEGER GENERATED BY DEFAULT AS IDENTITY (START WITH 1 INCREMENT BY 1) NOT NULL, EDUCATION VARCHAR(255), PRIMARY KEY (ID))
CREATE TABLE CUSTOMER_EDUCATION (Customer_ID INTEGER NOT NULL, educations_ID INTEGER NOT NULL, PRIMARY KEY (Customer_ID, educations_ID))
ALTER TABLE HEALTHINSURANCE ADD CONSTRAINT UNQ_HEALTHINSURANCE_2 UNIQUE (HEALTH_INSURANCE)
ALTER TABLE CUSTOMER ADD CONSTRAINT FK_CUSTOMER_HEALTHINSURANCE_ID FOREIGN KEY (HEALTHINSURANCE_ID) REFERENCES HEALTHINSURANCE (ID)
ALTER TABLE CUSTOMER ADD CONSTRAINT FK_CUSTOMER_SALUTATION_ID FOREIGN KEY (SALUTATION_ID) REFERENCES SALUTATION (ID)
ALTER TABLE ADDRESS ADD CONSTRAINT FK_ADDRESS_CUSTOMER_ID FOREIGN KEY (CUSTOMER_ID) REFERENCES CUSTOMER (ID)
ALTER TABLE CUSTOMER_EDUCATION ADD CONSTRAINT FK_CUSTOMER_EDUCATION_educations_ID FOREIGN KEY (educations_ID) REFERENCES EDUCATION (ID)
ALTER TABLE CUSTOMER_EDUCATION ADD CONSTRAINT FK_CUSTOMER_EDUCATION_Customer_ID FOREIGN KEY (Customer_ID) REFERENCES CUSTOMER (ID)
